const rows = $input.all().map(i => i.json);
const totalIngresos = rows.reduce((s, r) => s + Number(r.total_ingresos || 0), 0);
const totalEgresos = rows.reduce((s, r) => s + Number(r.total_egresos || 0), 0);
const sessions = new Set(rows.map(r => r.session_id));

// Aggregate by method for chart
const methodMap = {};
for (const r of rows) {
  const key = `${r.payment_method}|${r.currency}`;
  if (!methodMap[key]) methodMap[key] = { payment_method: r.payment_method, currency: r.currency, total_ingresos: 0, total_egresos: 0 };
  methodMap[key].total_ingresos += Number(r.total_ingresos || 0);
  methodMap[key].total_egresos += Number(r.total_egresos || 0);
}

return [{ json: {
  summary: {
    total_ingresos: totalIngresos,
    total_egresos: totalEgresos,
    resultado: totalIngresos - totalEgresos,
    num_sesiones: sessions.size
  },
  by_method: Object.values(methodMap),
  rows
} }];

const rows = $input.all().map(i => i.json);
const amounts = rows.map(r => Number(r.amount || 0));
const totalCobrado = amounts.reduce((s, a) => s + a, 0);
const mayorCobro = amounts.length ? Math.max(...amounts) : 0;

const methodMap = {};
for (const r of rows) {
  if (!methodMap[r.payment_method]) methodMap[r.payment_method] = { payment_method: r.payment_method, total: 0, count: 0 };
  methodMap[r.payment_method].total += Number(r.amount || 0);
  methodMap[r.payment_method].count += 1;
}

return [{ json: {
  summary: {
    total_cobrado: totalCobrado,
    num_cobros: rows.length,
    promedio: rows.length ? totalCobrado / rows.length : 0,
    mayor_cobro: mayorCobro
  },
  by_method: Object.values(methodMap),
  rows
} }];

const rows = $input.all().map(i => i.json).map(r => ({
  ...r,
  total_invoiced: Number(r.total_invoiced || 0),
  total_paid:     Number(r.total_paid     || 0),
  saldo:          Number(r.saldo          || 0),
}));
const total_facturado = rows.reduce((s, r) => s + r.total_invoiced, 0);
const total_cobrado   = rows.reduce((s, r) => s + r.total_paid,     0);
const saldo_neto      = rows.reduce((s, r) => s + r.saldo,          0);
const num_con_deuda   = rows.filter(r => r.saldo > 0).length;
return [{ json: {
  summary: { total_facturado, total_cobrado, saldo_neto, num_pacientes: rows.length, num_con_deuda },
  rows
} }];

const rows = $input.all().map(i => i.json);
const total = rows.reduce((s, r) => s + Number(r.total || 0), 0);
const dias = rows.length ? rows.reduce((s, r) => s + Number(r.days_pending || 0), 0) / rows.length : 0;

return [{ json: {
  summary: {
    num_presupuestos: rows.length,
    total_potencial: total,
    dias_promedio: Math.round(dias),
    tasa_conversion: 0
  },
  rows
} }];
